    public function __construct(
        /** @var int Number of inputs submitted by the caller. */
        public readonly int $inputs,
        /** @var int Number of extraction results produced. */
        public readonly int $results,
        /** @var int Number of per-input errors. */
        public readonly int $errors,
        /** @var int Number of URI inputs that resolved to remote HTTP(S) URLs. */
        public readonly int $remoteUrls,
        /** @var int Number of HTML pages crawled or scraped. */
        public readonly int $pagesCrawled,
        /** @var int Number of downloaded non-HTML documents extracted from URLs. */
        public readonly int $documentsDownloaded
    ) { }
}

