/**
 * A form field extracted from a PDF's AcroForm or XFA structure.
 *
 * Populated by the PDF extractor when `PdfConfig.extract_form_fields` is
 * enabled and the document is a fillable form. Supports both AcroForm (standard)
 * and XFA (XML Forms Architecture) layers. When both are present, AcroForm fields
 * take priority (canonical fallback per PDF spec), and XFA-only fields are appended.
 * The collection is empty for non-form PDFs and for non-PDF formats.
 *
 * `PdfConfig.extract_form_fields`: crate.core.config.PdfConfig.extract_form_fields
 */
final class PdfFormField
{
    public function __construct(
        /** @var string Partial field name (the leaf name within the field hierarchy). */
        public readonly string $name,
        /** @var string Fully-qualified field name (dotted path from the form root). */
        public readonly string $fullName,
        /** @var FormFieldType Classified field type. */
        public readonly FormFieldType $fieldType,
        /** @var int Raw field-flags bitmask (read-only, required, multiline, …). */
        public readonly int $flags,
        /** @var ?string Current field value, if any. */
        public readonly ?string $value = null,
        /** @var ?string Default field value, if any. */
        public readonly ?string $defaultValue = null,
        /**
         * 1-indexed page the field's widget appears on. Currently always `None` for
         * AcroForm fields; page assignment is a deferred enhancement requiring spatial
         * analysis of widget annotations per page.
         *
         * @var ?int
         */
        public readonly ?int $page = null,
        /** @var ?BoundingBox Widget bounding box on its page, if known. */
        public readonly ?BoundingBox $bbox = null,
        /** @var ?int Maximum input length for text fields, if specified. */
        public readonly ?int $maxLength = null,
        /** @var ?string Tooltip / alternate field description, if present. */
        public readonly ?string $tooltip = null
    ) { }
}

/**
 * Excel workbook representation.
 *
 * Contains all sheets from an Excel file (.xlsx, .xls, etc.) with
 * extracted content and metadata.
 */
final class ExcelWorkbook
{
    public function __construct(
        /** @var array<ExcelSheet> All sheets in the workbook */
