        /** @var BoundingBox Bounding box in document coordinate space. */
        public readonly BoundingBox $boundingBox,
        /** @var float Fraction of the page area covered by this region (0.0 to 1.0). */
        public readonly float $areaFraction
    ) { }
}

/**
