final class QrBoundingBox
{
    public function __construct(
        /** @var int Horizontal pixel offset of the bounding box top-left corner. */
        public readonly int $x,
        /** @var int Vertical pixel offset of the bounding box top-left corner. */
        public readonly int $y,
        /** @var int Width of the bounding box in pixels. */
        public readonly int $width,
        /** @var int Height of the bounding box in pixels. */
        public readonly int $height
