/**
 * Audit report describing what the redaction processor found and how it replaced it.
 *
 * The redactor returns this alongside the rewritten content so compliance, replay, and
 * audit-log consumers can see exactly what fired. Offsets are relative to the *original*
 * pre-redaction `content` and are intended for audit reconstruction only — the original
 * bytes are dropped at the end of the pipeline.
 */
final class RedactionReport
{
    public function __construct(
        /** @var array<RedactionFinding> Individual redaction findings in original-source byte order. */
        public readonly array $findings,
        /** @var int Total number of redactions applied across the document. */
        public readonly int $totalRedacted
    ) { }
}

/**
 * One redaction event: which span was rewritten, why, and with what.
 */
final class RedactionFinding
{
    public function __construct(
        /** @var int Byte-offset start in the original (pre-redaction) `ExtractionResult::content`. */
        public readonly int $start,
        /** @var int Byte-offset end (exclusive) in the original `ExtractionResult::content`. */
        public readonly int $end,
        /** @var PiiCategory PII category that fired this redaction. */
        public readonly PiiCategory $category,
        /** @var RedactionStrategy Strategy applied to this finding (mask, hash, token-replace, drop). */
        public readonly RedactionStrategy $strategy,
        /**
         * String that replaced the original mention. Always present; for `Drop` the
         * replacement is the empty string.
         *
         * @var string
         */
        public readonly string $replacementToken
    ) { }
}

/**
 * A single changed cell within a table.
 *
 * Defined here (rather than only in `crate.diff`) so `RevisionDelta` can
 * reference it unconditionally, without requiring the `diff` Cargo feature.
 * `crate.diff` re-exports this type verbatim.
 */
final class CellChange
{
    public function __construct(
        /** @var int Zero-based row index. */
        public readonly int $row,
        /** @var int Zero-based column index. */
        public readonly int $col,
        /** @var string Value before the change. */
        public readonly string $from,
        /** @var string Value after the change. */
        public readonly string $to
    ) { }
}

/**
 * A single tracked change embedded in a document.
 *
 * Populated by per-format extractors that understand change-tracking metadata
 * (DOCX `w:ins`/`w:del`/`w:rPrChange`, ODT `text:change-*`, …). Every
 * extractor defaults to `ExtractionResult.revisions = None` until a
 * format-specific implementation is added.
 */
final class DocumentRevision
{
    public function __construct(
        /**
         * Format-specific revision identifier.
         *
         * For DOCX this is the `w:id` attribute value on the change element
         * (e.g. `"42"`). When the attribute is absent a synthetic fallback is
         * generated (`"docx-ins-0"`, `"docx-del-3"`, …).
         *
         * @var string
         */
        public readonly string $revisionId,
        /** @var RevisionKind Semantic kind of this revision. */
        public readonly RevisionKind $kind,
        /** @var RevisionDelta The content changes that make up this revision. */
        public readonly RevisionDelta $delta,
        /** @var ?string Display name of the author who made this change, when available. */
        public readonly ?string $author = null,
        /**
         * ISO-8601 timestamp of the change, when available.
         *
         * Stored as a plain string so this type remains FFI-friendly and
         * unconditionally available without the `chrono` optional dep.
         * DOCX populates this from the `w:date` attribute (e.g.
         * `"2024-03-15T10:30:00Z"`).
         *
         * @var ?string
         */
        public readonly ?string $timestamp = null,
        /**
         * Best-effort document location for this revision.
         *
         * Resolution is format-dependent and may be `None` when the location
         * cannot be determined (e.g. changes inside table cells before
         * table-cell anchor support is added).
         *
         * @var ?RevisionAnchor
         */
        public readonly ?RevisionAnchor $anchor = null
    ) { }
}

/**
 * The content changes that make up a single revision.
 *
 * For insertions and deletions the `content` field carries the added/removed
 * lines as `DiffLine.Added` / `DiffLine.Removed` entries. For format
 * changes, `content` is empty — the property diff is left as a TODO for a
 * later enrichment pass.
 */
final class RevisionDelta
{
    public function __construct(
        /** @var array<DiffLine> Line-level content changes for this revision. */
        public readonly array $content,
        /** @var array<CellChange> Cell-level table changes for this revision. */
        public readonly array $tableChanges
    ) { }
}

/**
 * Summary of an extracted document.
 */
final class DocumentSummary
{
    public function __construct(
        /** @var string Summary text (plain prose). */
        public readonly string $text,
        /** @var SummaryStrategy Strategy that produced this summary. */
        public readonly SummaryStrategy $strategy,
        /** @var ?int Approximate token count of the summary, when known. */
        public readonly ?int $tokenCount = null
    ) { }
}

/**
 * Extracted table structure.
 *
 * Represents a table detected and extracted from a document (PDF, image, etc.).
 * Tables are converted to both structured cell data and Markdown format.
